hooks.command:
python3 -c "
import sys, json, re, subprocess

try:
    data = json.load(sys.stdin)
except:
    sys.exit(0)

command = data.get('tool_input', {}).get('command', '')
if 'git commit' not in command:
    sys.exit(0)

try:
    result = subprocess.run(
        ['git', 'diff', '--cached', '--name-only'],
        capture_output=True, text=True, timeout=10
    )
    staged_files = result.stdout.strip().splitlines()
except:
    sys.exit(0)

md_files = [f for f in staged_files if f.endswith('.md')]
if not md_files:
    sys.exit(0)

version_header_re = re.compile(r'^\*\*Version:\*\*\s*(.+)', re.MULTILINE)
table_row_re = re.compile(r'^\|\s*(?:SOP\s+|v)?([0-9]+\.[0-9]+(?:\.[0-9]+)?)\s*\|', re.MULTILINE)
changelog_re = re.compile(r'^\*v?([0-9]+\.[0-9]+(?:\.[0-9]+)?)\b', re.MULTILINE)

def extract_numeric(raw):
    raw = raw.strip()
    raw = re.sub(r'^(SOP\s+|v|V)', '', raw)
    m = re.match(r'^([0-9]+\.[0-9]+(?:\.[0-9]+)?)', raw)
    return m.group(1) if m else None

def vtuple(v):
    try:
        return tuple(int(x) for x in v.split('.'))
    except:
        return (0,)

errors = []

for rel_path in md_files:
    try:
        with open(rel_path, 'r', encoding='utf-8', errors='replace') as f:
            content = f.read()
    except:
        continue

    header_match = version_header_re.search(content)
    if not header_match:
        continue

    header_version = extract_numeric(header_match.group(1))
    if not header_version:
        continue

    log_versions = table_row_re.findall(content) + changelog_re.findall(content)
    if not log_versions:
        continue

    highest = max(log_versions, key=vtuple)

    if vtuple(header_version) != vtuple(highest):
        errors.append((rel_path, header_version, highest))

if errors:
    print('')
    print('VERSION GATE -- COMMIT BLOCKED')
    print('Global Lesson 38: Version header must match highest log entry.')
    print('')
    for path, header, log in errors:
        print('  FILE:    ' + path)
        print('  HEADER:  **Version:** ' + header)
        print('  LOG MAX: ' + log)
        print('  FIX:     Update **Version:** header to ' + log + ', or add a log entry for ' + header)
        print('')
    sys.exit(1)

sys.exit(0)
"
